"use client";
import { useState } from "react";
import {
  PlusCircle,
  Tag,
  MapPin,
  Calendar,
  ScrollText,
  Image,
  CheckCircle,
  Upload,
} from "lucide-react";

// Mock function for submission (replace with your actual API/Firebase logic)
const mockSubmitReport = async (data) => {
  // Simulate the time taken to process and upload the file
  return new Promise((resolve) => {
    setTimeout(() => {
      // In a real application, you would upload the file here and get a final URL.
      // For this mock, we'll just log the file name if it exists.
      const submittedData = { ...data };
      if (submittedData.imageFile) {
        submittedData.imageName = submittedData.imageFile.name;
        delete submittedData.imageFile; // Remove the large File object before logging/resolving
      }
      console.log("Mock Submission Successful:", submittedData);
      resolve({ success: true, id: Math.random().toString(36).substring(7) });
    }, 1500);
  });
};

export default function ReportFoundItemForm() {
  const initialFormState = {
    name: "",
    category: "",
    location: "",
    description: "",
    date: new Date().toISOString().split("T")[0],
    imageFile: null, // Changed from imageURL to imageFile
    reportedBy: "",
  };

  const [formData, setFormData] = useState(initialFormState);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState(null);

  const categories = [
    "Electronics",
    "Wallet",
    "Keys",
    "Textbook",
    "Clothing",
    "Jewelry",
    "Bags/Backpacks",
    "Documents",
    "Other",
  ];

  const handleChange = (e) => {
    const { name, value, files } = e.target;

    // Handle file input separately
    if (name === "imageFile" && files && files.length > 0) {
      setFormData((prev) => ({ ...prev, [name]: files[0] }));
    } else {
      setFormData((prev) => ({ ...prev, [name]: value }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage(null);
    setIsSubmitting(true);

    // Basic Validation Check (image is optional)
    if (
      !formData.name ||
      !formData.category ||
      !formData.location ||
      !formData.description
    ) {
      setMessage({
        type: "error",
        text: "Please fill out all required fields.",
      });
      setIsSubmitting(false);
      return;
    }

    try {
      const token = localStorage.getItem("accessToken");
      if (!token) {
        setMessage({
          type: "error",
          text: "Please login to submit a report.",
        });
        setIsSubmitting(false);
        return;
      }

      // Create FormData to handle file upload
      const formDataToSend = new FormData();
      formDataToSend.append("itemName", formData.name);
      formDataToSend.append("category", formData.category);
      formDataToSend.append("location", formData.location);
      formDataToSend.append("description", formData.description);
      formDataToSend.append("date", formData.date);

      // Append image file if provided
      if (formData.imageFile) {
        formDataToSend.append("photos", formData.imageFile);
      }

      const res = await fetch("http://localhost:5000/report/foundItem", {
        method: "POST",
        headers: {
          Authorization: `Bearer ${token}`,
          // Don't set Content-Type header - browser will set it with boundary for FormData
        },
        body: formDataToSend,
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.message || "Failed to submit");
      }

      setMessage({
        type: "success",
        text: "Report successful! Thank you for helping.",
      });

      setFormData(initialFormState);
    } catch (error) {
      console.error(error);
      setMessage({ type: "error", text: "Submission failed. Try again." });
    } finally {
      setIsSubmitting(false);
    }
  };

  const InputField = ({
    icon: Icon,
    label,
    name,
    type = "text",
    required = true,
    placeholder,
    children,
    className = "",
  }) => (
    <div className={`space-y-1 ${className}`}>
      <label htmlFor={name} className="block text-sm font-medium text-gray-700">
        {label} {required && <span className="text-red-500">*</span>}
      </label>
      <div className="relative">
        <Icon className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
        {children || (
          <input
            id={name}
            name={name}
            type={type}
            placeholder={placeholder}
            value={type !== "file" ? formData[name] : undefined}
            onChange={handleChange}
            required={required}
            disabled={isSubmitting}
            // Adjusted padding for standard input types
            className="w-full h-12 border border-gray-300 rounded-xl p-3 pl-10 focus:outline-none focus:ring-2 focus:ring-blue-400 transition duration-200 shadow-sm"
          />
        )}
      </div>
    </div>
  );

  return (
    // Removed min-h-screen to prevent unnecessary vertical space and scrolling
    <div className="bg-gray-50 p-4 sm:p-8 flex justify-center items-start">
      <div className="w-full max-w-3xl bg-white rounded-2xl shadow-2xl p-6 sm:p-10 my-4 border-t-4 border-blue-600">
        <div className="flex items-center space-x-3 mb-8 pb-4 border-b">
          <PlusCircle className="w-8 h-8 text-blue-600" />
          <h1 className="text-3xl font-bold text-indigo-700">
            Report a Found Item
          </h1>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Two-Column Grid for Primary Fields (sm breakpoint and up) */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            {/* 1. Item Name */}
            <InputField
              icon={Tag}
              label="Item Name"
              name="name"
              placeholder="e.g., Black Leather Wallet"
            />

            {/* 2. Category Dropdown */}
            <InputField icon={Tag} label="Category" name="category">
              <select
                id="category"
                name="category"
                value={formData.category}
                onChange={handleChange}
                required
                disabled={isSubmitting}
                className="w-full h-12 border border-gray-300 bg-white rounded-xl p-3 pl-10 focus:outline-none focus:ring-2 focus:ring-blue-400 transition duration-200 shadow-sm appearance-none cursor-pointer"
              >
                <option value="" disabled>
                  Select a category
                </option>
                {categories.map((cat) => (
                  <option key={cat} value={cat}>
                    {cat}
                  </option>
                ))}
              </select>
            </InputField>

            {/* 3. Found Location */}
            <InputField
              icon={MapPin}
              label="Exact Location Found"
              name="location"
              placeholder="e.g., Library 3rd Floor"
            />

            {/* 4. Date Found */}
            <InputField
              icon={Calendar}
              label="Date Found"
              name="date"
              type="date"
              required={false}
            />
          </div>

          {/* 5. Description (Full Width) */}
          <div className="col-span-full">
            <label
              htmlFor="description"
              className="block text-sm font-medium text-gray-700"
            >
              Description (Required) <span className="text-red-500">*</span>
            </label>
            <div className="relative mt-1">
              <ScrollText className="absolute left-3 top-3 w-5 h-5 text-gray-400" />
              <textarea
                id="description"
                name="description"
                placeholder="Describe the item, including color, distinguishing marks, and any unique details to help confirm ownership."
                value={formData.description}
                onChange={handleChange}
                required
                rows={4}
                disabled={isSubmitting}
                className="w-full border border-gray-300 rounded-xl p-3 pl-10 focus:outline-none focus:ring-2 focus:ring-blue-400 transition duration-200 shadow-sm"
              />
            </div>
          </div>

          {/* 6. Image Upload (File Input) - Full Width */}
          <div className="space-y-1 col-span-full">
            <label
              htmlFor="imageFile"
              className="block text-sm font-medium text-gray-700"
            >
              Upload Item Photo (Optional)
            </label>
            <div className="relative border-2 border-dashed border-gray-300 p-4 rounded-xl flex flex-col items-center justify-center bg-gray-50 hover:bg-gray-100 transition duration-200">
              <Upload className="w-6 h-6 text-gray-500 mb-2" />
              <p className="text-sm text-gray-600">
                {formData.imageFile
                  ? `File Selected: ${formData.imageFile.name}`
                  : "Drag and drop or click to select a file"}
              </p>
              <input
                id="imageFile"
                name="imageFile"
                type="file"
                accept="image/*"
                onChange={handleChange}
                disabled={isSubmitting}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
              />
            </div>
          </div>

          {/* Status Message (Full Width) */}
          {message && (
            <div
              className={`p-4 rounded-xl flex items-center space-x-3 col-span-full ${
                message.type === "error"
                  ? "bg-red-100 text-red-700"
                  : "bg-green-100 text-green-700"
              }`}
            >
              <CheckCircle className="w-5 h-5" />
              <p className="font-medium text-sm">{message.text}</p>
            </div>
          )}

          {/* Submission Button (Full Width) */}
          <button
            type="submit"
            disabled={isSubmitting}
            className={`w-full py-3 mt-4 text-white font-semibold rounded-xl transition duration-300 flex items-center justify-center space-x-3 shadow-lg 
              ${
                isSubmitting
                  ? "bg-blue-400 cursor-not-allowed"
                  : "bg-blue-600 hover:bg-blue-700 active:scale-[0.99]"
              }`}
          >
            {isSubmitting ? (
              <>
                <svg className="animate-spin h-5 w-5" viewBox="0 0 24 24">
                  <circle
                    className="opacity-25"
                    cx="12"
                    cy="12"
                    r="10"
                    stroke="currentColor"
                    strokeWidth="4"
                  ></circle>
                  <path
                    className="opacity-75"
                    fill="currentColor"
                    d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                  ></path>
                </svg>
                <span>Submitting Report...</span>
              </>
            ) : (
              <>
                <PlusCircle className="w-5 h-5" />
                <span>Submit Found Item Report</span>
              </>
            )}
          </button>
        </form>
      </div>
    </div>
  );
}
